import re
from pathlib import Path

AC_UID = "m6_baseline_provenance_scoping"
AC_TYPE = "hook"

AGENT_MD = Path(__file__).resolve().parents[3] / "agents" / "changelog-analyst.md"


def test_AC_10_M6_baseline_provenance_scoping():
    """
    GIVEN: agents/changelog-analyst.md Phase 2 provenance filter section is read
    WHEN:  the role of baseline_head_sha diff is inspected
    THEN:  the text explicitly states baseline diff is sanity-check only and
           NEVER an independent inclusion source for files outside the whitelist.
    """
    text = AGENT_MD.read_text()
    # Provenance sanity-check scoping
    assert re.search(r"provenance sanity check|sanity check for", text, re.IGNORECASE), \
        "baseline_head_sha sanity-check scoping clause missing"
    # Explicit "NEVER an inclusion source" guard
    assert re.search(r"NEVER an? .*inclusion source|never an inclusion source", text, re.IGNORECASE), \
        "explicit 'NEVER an inclusion source' guard missing — risk of foreign-session re-inclusion"
    # Files not in whitelist cannot be added via baseline diff
    assert re.search(r"not in the whitelist cannot be added", text, re.IGNORECASE), \
        "explicit 'not in whitelist cannot be added via baseline diff' clause missing"
